def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.zeros_like(bins, dtype=float)
    for i in range(len(bins)):
        capacity = bins[i]
        if capacity == 0:
            priorities[i] = np.inf
            continue
        ratio = item / capacity
        if ratio > 2:
            priorities[i] = ratio ** 3 + np.log(ratio) * 2
        elif 1 < ratio <= 2:
            priorities[i] = (ratio - 1) ** -2 + np.exp(ratio - 1)
        elif 0.7 < ratio <= 1:
            priorities[i] = 1 / (1 - ratio + 1e-12) + np.sin(5 * ratio)
        elif 0.3 < ratio <= 0.7:
            sum_exp = 0
            count = 0
            for j in range(1, 7):
                val = ratio + j * 0.08
                if val < 1:
                    sum_exp += np.exp(-val * 10)
                    count += 1
            priorities[i] = (sum_exp / (count if count > 0 else 1)) * 5
        else:
            prod_log = 1
            for k in range(1, 4):
                val = ratio + k * 0.05
                if val < 1:
                    prod_log *= np.log(1 - val + 1e-12) ** 2
            priorities[i] = -prod_log * 10
        if priorities[i] < 0:
            priorities[i] = abs(priorities[i]) + ratio * 3
    finite_priorities = priorities[np.isfinite(priorities)]
    if finite_priorities.size > 0:
        max_priority = np.max(finite_priorities)
    else:
        max_priority = 1
    for i in range(len(priorities)):
        if np.isinf(priorities[i]) or np.isnan(priorities[i]):
            priorities[i] = max_priority * 3
    return priorities
